// Fontes fase 1 (spec 2026-07-11). Passageiro de Primeira FORA por decisão do owner.
return [
  { json: { source: 'melhorescartoes', url: 'https://www.melhorescartoes.com.br/c/promocoes-milhas/feed/' } },
  { json: { source: 'pontospravoar', url: 'https://pontospravoar.com/category/promocoes/feed/' } },
  { json: { source: 'melhoresdestinos', url: 'https://www.melhoresdestinos.com.br/milhas/feed' } },
]

// RSS item -> shape estável. source vem do node gmpi-feeds via pairedItem.
const src = $('gmpi-feeds').item.json.source
const j = $json
const externalId = (j.guid || j.link || '').toString().slice(0, 500)
if (!externalId) return null // item sem id rastreável: ignora
const content = (j['content:encoded'] || j.content || j.contentSnippet || '')
  .toString()
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .slice(0, 6000)
return {
  json: {
    source: src,
    external_id: externalId,
    title: (j.title || '').toString().slice(0, 300),
    link: (j.link || '').toString(),
    content,
    pub_date: (j.pubDate || j.isoDate || '').toString(),
  },
}

// Junta metadados (gmpi-unseen carrega via RETURNING) + corpo do artigo.
// Preserva os hrefs como 'texto (url)' pro LLM enxergar o link de participação.
const meta = $('gmpi-unseen').item.json
let articleText = ''
const html = typeof $json.data === 'string' ? $json.data : ''
if (html && html.length > 200) {
  // Corta no <article>: header/menu dos blogs consomem o orçamento de texto antes do corpo.
  const artIdx = html.search(/<article\b/i)
  const scope = artIdx > 0 ? html.slice(artIdx) : html
  articleText = scope
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<a\b[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi, (m, href, txt) => {
      const t = txt.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim()
      return href.startsWith('http') ? ` ${t} (${href}) ` : ` ${t} `
    })
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .slice(0, 12000)
}
if (!articleText) articleText = meta.content || ''
return { json: { ...meta, article_text: articleText } }

// Valida o JSON do LLM e calcula a chave canônica (determinística, fora do LLM).
// norm vem de gmpi-unseen (que carrega o payload no RETURNING): a referência só
// atravessa o httpRequest 1:1 — nunca um Postgres que muda a contagem de itens.
const norm = $('gmpi-unseen').item.json
let out
try {
  const text = $json.content?.[0]?.text ?? ''
  out = JSON.parse(text.replace(/^[\s`]*json/i, '').replace(/`+/g, '').trim())
} catch (e) {
  return { json: { is_promo: false, parse_error: true, source: norm.source, link: norm.link } }
}
const CATS = ['transfer', 'shopping', 'miles', 'cards']
if (!out || out.is_promo !== true || !CATS.includes(out.category) || !out.title) {
  return { json: { is_promo: false, source: norm.source, link: norm.link } }
}
// Higiene do link de participação: nunca blog, sem utm_* (cliente não vê a origem).
// Regex puro: o sandbox do Code node NÃO expõe o global URL (new URL lançava e o catch anulava tudo).
if (out.cta_url) {
  const cu = String(out.cta_url)
  if (!/^https?:\/\//i.test(cu) || /pontospravoar|melhorescartoes|melhoresdestinos/i.test(cu)) {
    out.cta_url = null
  } else {
    out.cta_url = cu
      .replace(/([?&])utm_[^=&#]+=[^&#]*/gi, '$1')
      .replace(/\?&/, '?')
      .replace(/&&+/g, '&')
      .replace(/[?&]+$/, '')
  }
}
// Guarda anti-alucinação do milheiro: o número tem que estar LITERALMENTE no artigo
// (grafias 15,58 / 15.58 / inteiro com borda de dígito), faixa R$ 1–200. Regex puro
// (sandbox sem globals). $('gmpi-prep') atravessa só o gmpi-extract (httpRequest 1:1) — seguro.
{
  const rawCost = out.milheiro_cost
  out.milheiro_cost = null
  const costNum = typeof rawCost === 'number' ? rawCost : parseFloat(String(rawCost ?? '').replace(',', '.'))
  if (Number.isFinite(costNum) && costNum >= 1 && costNum <= 200) {
    const article = String($('gmpi-prep').item.json.article_text || '')
    const forms = [costNum.toFixed(2).replace('.', ','), costNum.toFixed(2)]
    if (Number.isInteger(costNum)) forms.push(String(costNum))
    const hit = forms.some((f) => new RegExp('(?<!\\d)' + f.replace('.', '\\.') + '(?!\\d)').test(article))
    if (hit) out.milheiro_cost = costNum
  }
  out.milheiro_note =
    out.milheiro_cost != null && out.milheiro_note ? String(out.milheiro_note).slice(0, 200) : null
}
const slug = (s) => (s || 'x').toString().toLowerCase().normalize('NFD').replace(/[^a-z0-9]+/g, '-')
const canonicalKey = [
  out.category,
  slug(out.source_program) + '>' + slug(out.target_program),
  out.bonus_numeric ?? slug(out.bonus_value),
  out.valid_until || 'sem-data',
].join(':')
return {
  json: {
    is_promo: true,
    ...out,
    canonical_key: canonicalKey,
    source_name:
      { melhorescartoes: 'Melhores Cartões', pontospravoar: 'Pontos pra Voar', melhoresdestinos: 'Melhores Destinos' }[norm.source] || norm.source,
    source_url: norm.link,
    raw_title: norm.title,
  },
}
